Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class PlatformAndEnvironmentTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public PlatformAndEnvironmentTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only (skipped on Linux/macOS)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsInstallPath()
    {
        var value = Microsoft.Win32.Registry.GetValue(
            @"HKEY_LOCAL_MACHINE\SOFTWARE\MyApp", "InstallPath", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_UsesGpu_ProducesOutput()
    {
        var frame = GpuRenderer.RenderFrame(1920, 1080);
        Assert.IsNotNull(frame);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var client = new WeatherClient();
        var forecast = await client.GetForecastAsync("Seattle",
            _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Temp file cleanup — [TestCleanup] runs even on failure
    [TestMethod]
    public void Export_WritesToTempFile()
    {
        _tempFile = Path.GetTempFileName();
        var exporter = new DataExporter();

        exporter.Export(_tempFile);

        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Summary of attributes used:**

| Scenario | Attribute | MSTest version |
|----------|-----------|----------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retry | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` | All versions |

`[TestCleanup]` always runs after the test method, regardless of pass/fail, making it ideal for resource cleanup. For `IDisposable` resources, you can also implement `IDisposable`/`IAsyncDisposable` on the test class — MSTest calls `Dispose` after cleanup.
